-- ============================================
-- 023: 從愛露營匯入特性標籤種子資料
-- 來源：m.icamping.app (2026-03-05)
-- 總計：1408 筆投票，涵蓋 243 個已比對營地
-- ============================================

-- Step 1: 讓 feature_votes.user_id 可為 NULL（系統種子資料使用）
ALTER TABLE feature_votes
  ALTER COLUMN user_id DROP NOT NULL,
  ALTER COLUMN user_id DROP DEFAULT;

-- Step 2: 移除原本的 FK constraint，改為允許 NULL
-- 找到並修改 constraint
DO $$
DECLARE
  c_name TEXT;
BEGIN
  SELECT constraint_name INTO c_name
  FROM information_schema.table_constraints
  WHERE table_name = 'feature_votes'
    AND constraint_type = 'FOREIGN KEY'
    AND constraint_name LIKE '%user_id%';
  IF c_name IS NOT NULL THEN
    EXECUTE format('ALTER TABLE feature_votes DROP CONSTRAINT %I', c_name);
    EXECUTE format(
      'ALTER TABLE feature_votes ADD CONSTRAINT %I FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE',
      c_name
    );
  END IF;
END $$;

